{"code": "import json
import re

books_info_path = locals()['var_functions.query_db:26']
with open(books_info_path, 'r') as f:
    books_info_data = json.load(f)

# Extract publication years more carefully
books_with_year = []
for book in books_info_data:
    details = book.get('details', '')
    # Try different approaches to find year
    year = None

    # Method 1: Look for patterns like "January 1, 2004" or "May 20, 1996"
    date_pattern = r'(January|February|March|April|May|June|July|August|September|October|November|December)\s+\d{1,2},\s+(\d{4})'
    match = re.search(date_pattern, details)
    if match:
        year = int(match.group(2))
    else:
        # Method 2: Look for "published on" patterns
        publish_pattern = r'published on.*?\b(19\d{2}|20\d{2})\b'
        match = re.search(publish_pattern, details, re.IGNORECASE)
        if match:
            year = int(match.group(1))
        else:
            # Method 3: Look for "published in YEAR"
            in_pattern = r'published in\s+(19\d{2}|20\d{2})'
            match = re.search(in_pattern, details, re.IGNORECASE)
            if match:
                year = int(match.group(1))
            else:
                # Method 4: Look for any 4-digit year in 1900-2023 range
                year_pattern = r'\b(19\d{2}|20[0-2]\d)\b'
                matches = re.findall(year_pattern, details)
                if matches:
                    year = int(matches[0])

    if year:
        books_with_year.append({
            'book_id': book['book_id'],
            'title': book['title'],
            'year': year
        })

print("__RESULT__:")
print(json.dumps({
    "total_books": len(books_info_data),
    "books_with_year": len(books_with_year),
    "sample_books": books_with_year[:10],
    "years_range": {
        "min": min([b['year'] for b in books_with_year]) if books_with_year else None,
        "max": max([b['year'] for b in books_with_year]) if books_with_year else None
    }
}))"}
